import { Link, useLocation } from "react-router-dom";


export default function Header() {
  const location = useLocation();

  const links = [
    { path: "/dashboard", name: "Dashboard" },
    { path: "/projects", name: "Projects" },
    { path: "/taches", name: "Tasks" },
    { path: "/chat", name: "Chat" },
    { path: "/rapports", name: "Reports" },
  ];

  return (
    <header className="header">
      {/* LEFT: Logo */}
      <div className="left">
        <img src='' alt="logo" className="logo" />
      </div>

      {/* CENTER: Navigation */}
      <nav className="center">
        {links.map((link) => (
          <Link
            key={link.path}
            to={link.path}
            className={
              location.pathname === link.path ? "nav-link active" : "nav-link"
            }
          >
            {link.name}
          </Link>
        ))}
      </nav>

      {/* RIGHT: User */}
      <div className="right">
        <button className="btn">+ New Project</button>

        <div className="user">
          <img
            src="https://i.pravatar.cc/40"
            alt="user"
            className="avatar"
          />
        </div>
      </div>
    </header>
  );
}
